import Vue from 'vue'
import Vuex from 'vuex'
import axios from 'axios'

Vue.use(Vuex)

const API_URL = 'http://localhost:3000/api'

export default new Vuex.Store({
  state: {
    trimestre: 'Q1',
    salesData: {},   // Ahora se llena desde el backend
    users: [],       // datos reales desde backend (proxy JSONPlaceholder)
    loading: false,
    error: null
  },

  getters: {
    // Datos del trimestre activo (si no hay datos, retornamos estructura vacía para evitar errores)
    currentData: state => state.salesData[state.trimestre] || {
      kpis: { total: 0, orders: 0, ticket: 0, metaPct: 0 },
      months: [],
      ventas: [],
      metas: [],
      regiones: [],
      vendedores: []
    },
    kpis: (state, getters) => getters.currentData.kpis,
    chartData: (state, getters) => ({
      months: getters.currentData.months,
      ventas: getters.currentData.ventas,
      metas: getters.currentData.metas
    }),
    regiones: (state, getters) => getters.currentData.regiones,
    vendedores: (state, getters) => getters.currentData.vendedores,

    vendedoresConEstado: (state, getters) =>
      getters.vendedores.map(v => ({
        ...v,
        pct: v.meta > 0 ? Math.round((v.ventas / v.meta) * 100) : 0,
        estado: v.ventas >= v.meta ? 'green' : v.ventas >= v.meta * 0.85 ? 'amber' : 'red'
      })),

    topVendedor: (state, getters) =>
      getters.vendedores.length > 0
        ? [...getters.vendedores].sort((a, b) => b.ventas - a.ventas)[0]
        : { name: '...', ventas: 0 }
  },

  mutations: {
    SET_TRIMESTRE(state, trimestre) {
      state.trimestre = trimestre
    },
    SET_SALES_DATA(state, { quarter, data }) {
      Vue.set(state.salesData, quarter, data)
    },
    SET_USERS(state, users) {
      state.users = users
    },
    SET_LOADING(state, value) {
      state.loading = value
    },
    SET_ERROR(state, error) {
      state.error = error
    }
  },

  actions: {
    // Cambia el trimestre activo y carga datos si no existen
    async cambiarTrimestre({ commit, state, dispatch }, trimestre) {
      commit('SET_TRIMESTRE', trimestre)
      if (!state.salesData[trimestre]) {
        await dispatch('fetchSalesData', trimestre)
      }
    },

    // Carga datos de ventas desde el backend
    async fetchSalesData({ commit }, trimestre) {
      commit('SET_LOADING', true)
      try {
        const response = await axios.get(`${API_URL}/sales/${trimestre}`)
        commit('SET_SALES_DATA', { quarter: trimestre, data: response.data })
      } catch (error) {
        commit('SET_ERROR', 'Error al cargar datos de ventas.')
        console.error('API Error:', error)
      } finally {
        commit('SET_LOADING', false)
      }
    },

    // Consume API real desde el backend
    async fetchUsers({ commit }) {
      commit('SET_LOADING', true)
      commit('SET_ERROR', null)
      try {
        const response = await axios.get(`${API_URL}/users`)
        commit('SET_USERS', response.data)
      } catch (error) {
        commit('SET_ERROR', 'Error al cargar los usuarios.')
        console.error('API Error:', error)
      } finally {
        commit('SET_LOADING', false)
      }
    }
  }
})
